const body = $input.first().json.body || $input.first().json;
const links = body.links || [];
if (!Array.isArray(links) || !links.length) throw new Error('links is required');
const language = body.language || 'zh+en';
const raw_text = body.raw_text || '';
return [{ json: { links, language, raw_text } }];

// raw_text 旁路：跳过抓取，直接按 openclaw handoff 格式构建
const links = $input.first().json.links || [];
const raw_text = $input.first().json.raw_text || '';
const url = links[0] || '';
const run_id = 'n8n-' + new Date().toISOString().slice(0,10) + '-' + Date.now().toString().slice(-4);

let source_type = 'web';
try {
  const host = new URL(url).hostname.toLowerCase();
  if (host.includes('youtu')) source_type = 'youtube';
  else if (host.includes('x.com') || host.includes('twitter')) source_type = 'x';
  else if (host.includes('xiaohongshu') || host.includes('xhslink')) source_type = 'xhs';
  else if (host.includes('weixin') || host.includes('wemp')) source_type = 'wechat';
} catch(e) {}

const item = {
  source_type,
  source_url: url,
  title: `${source_type} (本地转录注入)`,
  transcript: raw_text,
  language: $input.first().json.language || 'zh+en',
  meta: { chars: raw_text.length, method: 'manual_inject' }
};

return [{ json: {
  ok: true,
  run_id,
  items: [item],
  need_materials: raw_text.length < 300 ? [{ source_url: url, missing: '正文不足300字' }] : []
} }];

// 写临时文件 + 调 Python 脚本 + 解析输出，合并为一个节点
const { spawnSync } = require('child_process');
const fs = require('fs');
const path = require('path');

const links    = $input.first().json.links;
const language = $input.first().json.language;
const python   = '/home/ubuntu/.openclaw/workspace/.venv_stt/bin/python';
const script   = '/home/ubuntu/Auto-Grasp-Pipeline/scripts/collect_notes.py';
const cookies  = '/home/ubuntu/.openclaw/secrets/youtube_cookies.txt';

// 写临时 JSON 文件（防命令注入）
const tmpFile = path.join('/tmp', `harvest_${Date.now()}.json`);
fs.writeFileSync(tmpFile, JSON.stringify({ links, language }), 'utf8');

// 运行脚本（显式传 cookies 路径 + 注入环境变量）
const result = spawnSync(
  python,
  [script, '--links-file', tmpFile, '--format', 'json', '--cookies', cookies],
  { timeout: 600000, env: { ...process.env, YOUTUBE_COOKIES: cookies, VENV_PYTHON: python } }
);

try { fs.unlinkSync(tmpFile); } catch(e) {}

if (result.status !== 0) {
  const err = result.stderr?.toString() || result.stdout?.toString() || 'unknown error';
  throw new Error('Script failed: ' + err.slice(-500));
}

// 解析输出
const stdout = (result.stdout?.toString() || '').trim();
const lines  = stdout.split('\n').filter(l => l.trim());
let parsed;
try { parsed = JSON.parse(lines[lines.length - 1]); }
catch(e) { throw new Error('Parse failed: ' + stdout.slice(-300)); }

if (!parsed.ok) throw new Error('Script error: ' + JSON.stringify(parsed));

// 转换为 openclaw handoff 协议格式
const run_id = 'n8n-' + new Date().toISOString().slice(0,10) + '-' + Date.now().toString().slice(-4);

const items = (parsed.records || []).map(r => ({
  source_type: r.platform === 'xiaohongshu' ? 'xhs' : r.platform,
  source_url:  r.url,
  title:       r.title || '',
  transcript:  r.body  || '',
  language:    'zh+en',
  meta: { chars: (r.quality||{}).chars || 0, method: r.method || '' }
})).filter(i => i.transcript);

const need_materials = (parsed.need_materials || []).map(m => ({
  source_url:  m.source      || '',
  got:         m.got         || '',
  missing:     m.missing     || '',
  provide:     m.provide     || '',
  fail_reason: m.fail_reason || 'unknown',
  errors:      m.errors      || []
}));

return [{ json: { ok: true, run_id, items, need_materials } }];
